/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `students` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nisn` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nis` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nama_lengkap` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `gender` enum('L','P') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tempat_lahir` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tanggal_lahir` date DEFAULT NULL,
  `agama` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `alamat` text COLLATE utf8mb4_unicode_ci,
  `no_telepon` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nama_ayah` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nama_ibu` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nama_wali` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `no_telepon_ortu` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `qr_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `class_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `major_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `applicant_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_alumni` tinyint(1) NOT NULL DEFAULT '0',
  `graduation_year` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `graduation_date` date DEFAULT NULL,
  `registration_type` enum('baru','pindahan') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'baru',
  `origin_school` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `entry_date` date DEFAULT NULL,
  `entry_semester_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `exit_date` date DEFAULT NULL,
  `exit_reason` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes_buku_induk` text COLLATE utf8mb4_unicode_ci,
  `skl_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ijazah_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ijazah_scan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `students_nisn_unique` (`nisn`),
  UNIQUE KEY `students_nis_unique` (`nis`),
  UNIQUE KEY `students_qr_code_unique` (`qr_code`),
  UNIQUE KEY `students_skl_number_unique` (`skl_number`),
  UNIQUE KEY `students_ijazah_number_unique` (`ijazah_number`),
  KEY `students_user_id_foreign` (`user_id`),
  KEY `students_class_id_index` (`class_id`),
  KEY `students_applicant_id_foreign` (`applicant_id`),
  KEY `students_is_alumni_index` (`is_alumni`),
  KEY `students_graduation_year_index` (`graduation_year`),
  KEY `students_entry_semester_id_foreign` (`entry_semester_id`),
  KEY `students_major_id_foreign` (`major_id`),
  CONSTRAINT `students_applicant_id_foreign` FOREIGN KEY (`applicant_id`) REFERENCES `applicants` (`id`) ON DELETE SET NULL,
  CONSTRAINT `students_class_id_foreign` FOREIGN KEY (`class_id`) REFERENCES `school_classes` (`id`) ON DELETE SET NULL,
  CONSTRAINT `students_entry_semester_id_foreign` FOREIGN KEY (`entry_semester_id`) REFERENCES `semesters` (`id`) ON DELETE SET NULL,
  CONSTRAINT `students_major_id_foreign` FOREIGN KEY (`major_id`) REFERENCES `majors` (`id`) ON DELETE SET NULL,
  CONSTRAINT `students_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
